package com.example.eventstreamingplatform.service;

import java.time.Instant;
import java.util.UUID;

import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import com.example.eventstreamingplatform.model.EventMessage;

@Service
public class EventProducerService {

    private final KafkaTemplate<String, EventMessage> kafkaTemplate;

    public EventProducerService(KafkaTemplate<String, EventMessage> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publishEvent(String eventType, String payload) {
        EventMessage message = new EventMessage(
                UUID.randomUUID().toString(),
                eventType,
                payload,
                Instant.now()
        );
        kafkaTemplate.send("events-topic", message.getEventId(), message);
    }
}

package com.example.eventstreamingplatform.service;

import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

import com.example.eventstreamingplatform.model.EventMessage;

@Service
public class EventConsumerService {

    @KafkaListener(topics = "events-topic", groupId = "event-streaming-group")
    public void consume(EventMessage message) {
        System.out.println("Consumed event: " + message.getEventId() + " | " + message.getEventType() + " | " + message.getPayload());
    }
}

package com.example.eventstreamingplatform.controller;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import com.example.eventstreamingplatform.service.EventProducerService;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<String> publishEvent(@RequestParam String type, @RequestParam String payload) {
        eventProducerService.publishEvent(type, payload);
        return ResponseEntity.ok("Event published");
    }
}

